import java.io.*;
import java.util.*;

class Main {
    static class Node{int val; Node next; Node(int v){val=v;}};
    static int loopLengthMinusOne(Node head){Node slow=head, fast=head;while(fast!=null && fast.next!=null){slow=slow.next; fast=fast.next.next; if(slow==fast){int len=1; Node cur=slow.next; while(cur!=slow){len++; cur=cur.next;} return len-1;}}return -1;}
    public static void main(String[] args) throws Exception {
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st=new StringTokenizer(br.readLine());
        int T=Integer.parseInt(st.nextToken());
        StringBuilder sb=new StringBuilder();
        while(T-- > 0){
            st=new StringTokenizer(br.readLine());
            int N=Integer.parseInt(st.nextToken());
            int M=Integer.parseInt(st.nextToken());
            Node head=null, tail=null;
            for(int i=1;i<=N;i++){
                Node nd=new Node(i);
                if(head==null) head=tail=nd; else{tail.next=nd; tail=nd;}
            }
            if(M!=-1){
                Node target=head;
                for(int i=1;i<M;i++) target=target.next;
                tail.next=target;
            }
            sb.append(loopLengthMinusOne(head)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

