import sys

def loop_len_minus_one(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            length = 1
            cur = slow.next
            while cur is not slow:
                length += 1
                cur = cur.next
            return length - 1
    return -1

class Node:
    __slots__ = ('val','next')
    def __init__(self, v):
        self.val = v
        self.next = None

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        head = tail = None
        for i in range(1, N+1):
            nd = Node(i)
            if head is None:
                head = tail = nd
            else:
                tail.next = nd
                tail = nd
        if M != -1:
            target = head
            for _ in range(M-1):
                target = target.next
            tail.next = target
        out.append(str(loop_len_minus_one(head)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

